// Classify every authorized hold into one of three actions:
//   capture   → bid won + auction closed_sold → capture the PaymentIntent
//   release   → bid is outbid/forfeited/runner_up → cancel the PaymentIntent
//   skip      → auction still open or bid still active; come back later
//
// The embedded auction_bids + auctions arrive via PostgREST resource
// embedding (the `?select=...,auction_bids(...,auctions(...))` query).
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};

const holds = allOf('Fetch Authorized Holds');
if (holds.length === 0) {
  return [{ json: { _no_work: true, ts: new Date().toISOString() } }];
}

const out = [];
for (const h of holds) {
  const bid = h.auction_bids || null;
  const auction = bid && bid.auctions ? bid.auctions : null;
  if (!bid || !auction) {
    out.push({ json: { hold_id: h.id, action: 'skip', reason: 'embedded bid/auction missing', stripe_payment_intent_id: h.stripe_payment_intent_id, amount_cents: h.amount_cents } });
    continue;
  }
  const bidWon  = bid.status === 'won' && auction.status === 'closed_sold' && auction.winning_bid_id === bid.id;
  const release = (bid.status === 'outbid' || bid.status === 'forfeited' || bid.status === 'runner_up' || bid.status === 'rejected');
  if (bidWon) {
    out.push({ json: { hold_id: h.id, action: 'capture', stripe_payment_intent_id: h.stripe_payment_intent_id, amount_cents: h.amount_cents, bid_id: bid.id, auction_id: auction.id } });
  } else if (release) {
    out.push({ json: { hold_id: h.id, action: 'release', stripe_payment_intent_id: h.stripe_payment_intent_id, amount_cents: h.amount_cents, bid_id: bid.id, auction_id: auction.id, bid_status: bid.status } });
  } else {
    // Still in-flight — leave for next tick
  }
}

if (out.length === 0) return [{ json: { _no_work: true, ts: new Date().toISOString(), examined: holds.length } }];
return out;

// Inspect Stripe response, build the PATCH body for auction_payment_holds.
const input = $input.item.json;
const stripe = input;
const hold_id = $('Classify Holds').itemMatching($itemIndex).json.hold_id;
const action  = $('Classify Holds').itemMatching($itemIndex).json.action;
const pi_id   = $('Classify Holds').itemMatching($itemIndex).json.stripe_payment_intent_id;

const stripeStatus = stripe && stripe.status ? stripe.status : null;
const stripeErr    = stripe && stripe.error ? (stripe.error.message || stripe.error.code) : null;

let newStatus, completedField, failureReason = null;
if (action === 'capture') {
  if (stripeStatus === 'succeeded') {
    newStatus = 'captured'; completedField = 'captured_at';
  } else {
    newStatus = 'failed'; completedField = 'captured_at';
    failureReason = stripeErr || ('Stripe capture returned status: ' + (stripeStatus || 'unknown'));
  }
} else {
  // release
  if (stripeStatus === 'canceled') {
    newStatus = 'released'; completedField = 'released_at';
  } else {
    newStatus = 'failed'; completedField = 'released_at';
    failureReason = stripeErr || ('Stripe cancel returned status: ' + (stripeStatus || 'unknown'));
  }
}

const patchBody = { status: newStatus };
patchBody[completedField] = new Date().toISOString();
if (failureReason) patchBody.failure_reason = failureReason;

return { json: { hold_id: hold_id, action: action, payment_intent_id: pi_id, stripe_status: stripeStatus, new_status: newStatus, patch_body: patchBody } };
